template:
WITH search_sessions AS (
  SELECT DISTINCT session_id FROM events WHERE event_type = 'search' AND event_date BETWEEN {start_date} AND {end_date}
),
purchased_sessions AS (
  SELECT DISTINCT s.session_id FROM search_sessions s JOIN orders o ON s.session_id = o.session_id WHERE o.status = 'completed' AND o.order_date BETWEEN {start_date} AND {end_date}
)
SELECT COUNT(DISTINCT s.session_id) AS search_sessions, COUNT(DISTINCT p.session_id) AS purchased_sessions, COUNT(DISTINCT p.session_id) * 100.0 / NULLIF(COUNT(DISTINCT s.session_id), 0) AS conversion_rate FROM search_sessions s LEFT JOIN purchased_sessions p ON s.session_id = p.session_id
